mapper.select:
SELECT id, conversation_id, student_id, course_id, role, content, media_type, media_url, token_count, status, create_time
FROM edu_ai_message
WHERE conversation_id = #{conversationId}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT id, conversation_id, student_id, course_id, role, content, media_type, media_url, token_count, status, create_time
FROM edu_ai_message
WHERE student_id = #{studentId} AND course_id = #{courseId}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM edu_ai_message
WHERE student_id = #{studentId}
  AND course_id = #{courseId}
  AND role = 'user'
  AND DATE(create_time) = CURDATE()
